-- En el caso de UPDATE IF UPDATING THEN SELECT (SELECT ENVIO_BQ FROM TKRBQ_CONSULTAS WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NULL THEN
INSERT INTO TKRBQ_CONSULTAS ( ENVIO_BQ, ID, ID_PACIENTE, ID_CITA, ID_USUARIO_ATIENDE, ID_RAZON_CONSULTA, DETALLE_RAZON_CONSULTA, FECHA_CONSULTA, HISTORIA_ENFERMEDAD, HISTORIA_CLINICA, MEDICACIONES, ALERGIAS, HISTORIA_SOCIAL, RESULTADOS_EXAMENES, COMPONENTES_EXAMEN_FISICO, DIAGNOSTIVO_PRINCIPAL, EVALUACION, PLAN, ID_TIPO_CONSULTA, OTRO_TIPO_CONSULTA, MOTIVO_CONSULTA, PESO, ALTURA, HISTORIA_FAMILIAR, ID_CONDUCTA, OTRA_CONDUCTA, PRESCRIPCION_MEDICA, ANTECEDENTES_PERSONALES, ANTECEDENTES_PATOLOGICOS, ANTECEDENTES_QUIRURGICOS, ANTECEDENTES_TRAUMATICOS, ANTECEDENTES_FAMILIARES, ALERGICOS, FARMACOLOGICOS, RESULTADOS_DIAGNOSTICOS, OTROS_ENFERMEDAD_ACTUAL, ELEMENTOS_EXAMEN_FISICO, SOL_SERVICIO_ORDEN_MEDICA, REF_ESPECIALISTAS, FECHA_COND_ESPECIALISTA, FECHA_CITA_SEGUIMIENTO, DURACION_CONSULTA, HISTORIA_CLIENTE, OTROS_ANTECEDENTES, LECTURA_PESO_ANTERIORES, LABORATORIOS, ALERGIAS_INTOLERANCIAS, VITAMINAS_MINERALES, HIERBAS_MEDICINAS, COMIDAS_AUSENCIA_HAMBRE, EPISODIOS_ALIMENT_SIN_CONTROL, INTENTO_PREVIO_PERDIDA_PESO, CONSULTA_NUTRICIONAL_PREVIA, INQUIETUDES_REL_PESO, RECUERDO_HORAS, FREC_ALIM_BEBIDAS_AZUCARADAS, FREC_ALIM_FRUTAS, FREC_ALIM_VEGETALES, FREC_ALIM_COMIDA_DULCE, FREC_ALIM_COMIDA_REST_EVENTOS, FREC_ALIM_COMIDAS_DOMICILIO, FREC_ALIM_MERIENDAS, FREC_ALIM_ACTIVIDAD_FISICA, INTERVENCION_NUTRICIONAL, PRESCRIPCION_NUTRICIONAL, ASE_NUTRI_SOPORTE, ASE_NUTRI_METAS, ASE_NUTRI_EDUCACION_NUT, ASE_NUTR_REL_ALIM_SALUD, ASE_NUTR_AJUSTES, ASE_NUTRI_PANFLETO, ASE_NUTRI_ENTENDIMIENTO, COORDINACION_CUIDADO, META_NUTRICION_UNO, META_NUTRICION_DOS, META_NUTRICION_TRES, OTRO_DIAGNOSTICO, VISITA_APROPIADA, ID_ESTADO_CIVIL, PROFESION, ANTECEDENTES_OBSERVACIONES, APARIENCIA_COMPORTAMIENTO, LENGUAJE_COMUNICACION, CONTENIDO_PENSAMIENTO, FUNCIONAMIENTO_SENSORIAL_MOTOR, FUNCIONAMIENTO_COGNOSCITIVO, FUNCIONAMIENTO_MNEMICO, FUNCIONAMIENTO_EMOCIONAL, INSIGHT_JUICIO, ANALISIS, ID_MEDICAMENTOS, NUMERO_FILA_GSHEET, CERTIFICADO, RESUMEN_INTERCONSULTA, FECHA_INICIO_INCAPACIDAD, FECHA_FIN_INCAPACIDAD, TIPO_TRAMITE, RECOMENDACIONES, ID_PROFESIONAL_INTERCONSULTA, COMENTARIOS_INTERCONSULTA, ID_ESPECIALIDAD_INTERCONSULTA, JUSTIFICACION_INCAPACIDAD, ID_ESTADO_CONSULTA, URGENCIAS_HOSPITALIZACION, RESULTADOS_IMAGENES, INDICADOR_PRORROGA, FECHA_CREACION, CONDUCTA_CITA_VIRTUAL, ID_ORIGEN_INCAPACIDAD, TIPO_MONITOREO, ID_VARIABLES_MONITOREO, FECHA_INICIAL_MONITOREO, FECHA_FINAL_MONITOREO, BARTHEL, GLASGOW, ESAS, KARNOFSKY, PPS, PFEIFFER, PPI, TIPO_INTERCONSULTA, OTROS_ORDENAMIENTOS, FECHA_ATENCION, FECHA_FINALIZACION, ID_FINALIDAD, ID_CAUSA_EXTERNA, EPICRISIS ) VALUES ( 2, -- ENVIO_BQ por defecto :NEW.ID, :NEW.ID_PACIENTE, :NEW.ID_CITA, :NEW.ID_USUARIO_ATIENDE, :NEW.ID_RAZON_CONSULTA, :NEW.DETALLE_RAZON_CONSULTA, :NEW.FECHA_CONSULTA, :NEW.HISTORIA_ENFERMEDAD, :NEW.HISTORIA_CLINICA, :NEW.MEDICACIONES, :NEW.ALERGIAS, :NEW.HISTORIA_SOCIAL, :NEW.RESULTADOS_EXAMENES, :NEW.COMPONENTES_EXAMEN_FISICO, :NEW.DIAGNOSTIVO_PRINCIPAL, :NEW.EVALUACION, :NEW.PLAN, :NEW.ID_TIPO_CONSULTA, :NEW.OTRO_TIPO_CONSULTA, :NEW.MOTIVO_CONSULTA, :NEW.PESO, :NEW.ALTURA, :NEW.HISTORIA_FAMILIAR, :NEW.ID_CONDUCTA, :NEW.OTRA_CONDUCTA, :NEW.PRESCRIPCION_MEDICA, :NEW.ANTECEDENTES_PERSONALES, :NEW.ANTECEDENTES_PATOLOGICOS, :NEW.ANTECEDENTES_QUIRURGICOS, :NEW.ANTECEDENTES_TRAUMATICOS, :NEW.ANTECEDENTES_FAMILIARES, :NEW.ALERGICOS, :NEW.FARMACOLOGICOS, :NEW.RESULTADOS_DIAGNOSTICOS, :NEW.OTROS_ENFERMEDAD_ACTUAL, :NEW.ELEMENTOS_EXAMEN_FISICO, :NEW.SOL_SERVICIO_ORDEN_MEDICA, :NEW.REF_ESPECIALISTAS, :NEW.FECHA_COND_ESPECIALISTA, :NEW.FECHA_CITA_SEGUIMIENTO, :NEW.DURACION_CONSULTA, :NEW.HISTORIA_CLIENTE, :NEW.OTROS_ANTECEDENTES, :NEW.LECTURA_PESO_ANTERIORES, :NEW.LABORATORIOS, :NEW.ALERGIAS_INTOLERANCIAS, :NEW.VITAMINAS_MINERALES, :NEW.HIERBAS_MEDICINAS, :NEW.COMIDAS_AUSENCIA_HAMBRE, :NEW.EPISODIOS_ALIMENT_SIN_CONTROL, :NEW.INTENTO_PREVIO_PERDIDA_PESO, :NEW.CONSULTA_NUTRICIONAL_PREVIA, :NEW.INQUIETUDES_REL_PESO, :NEW.RECUERDO_HORAS, :NEW.FREC_ALIM_BEBIDAS_AZUCARADAS, :NEW.FREC_ALIM_FRUTAS, :NEW.FREC_ALIM_VEGETALES, :NEW